#include <Servo.h>
#include <Adafruit_NeoPixel.h>

Servo myServo;
Adafruit_NeoPixel strip(8, 8, NEO_GRB + NEO_KHZ800);

const int potPin = A0; 
const int servoPin = 9; 
const int neopixelPin = 8;

void setup() {
  myServo.attach(servoPin);
  pinMode(potPin, INPUT);
  strip.begin();
  strip.show();
}

void loop() {
  int potValue = analogRead(potPin);      
  int angle = map(potValue, 0, 1023, 0, 180); 
  myServo.write(angle);

  // Cycle through colors
  static unsigned long lastColorChange = 0;
  static int colorIndex = 0;

  if (millis() - lastColorChange > 500) {
    lastColorChange = millis();
    colorIndex = (colorIndex + 1) % 6;

    uint32_t color;
    switch(colorIndex) {
      case 0: color = strip.Color(255, 0, 0); break;      // Red
      case 1: color = strip.Color(255, 165, 0); break;    // Orange
      case 2: color = strip.Color(255, 255, 0); break;    // Yellow
      case 3: color = strip.Color(0, 255, 0); break;      // Green
      case 4: color = strip.Color(0, 0, 255); break;      // Blue
      case 5: color = strip.Color(128, 0, 128); break;    // Purple
    }

    for(int i = 0; i < strip.numPixels(); i++) {
      strip.setPixelColor(i, color);
    }
    strip.show();
  }

  delay(15); 
}

